item.description:
&lt;div id=&quot;toc&quot; class=&quot;toc&quot;&gt;
&lt;div id=&quot;toctitle&quot;&gt;Table of Contents&lt;/div&gt;
&lt;ul class=&quot;sectlevel1&quot;&gt;
&lt;li&gt;&lt;a href=&quot;#_intégration_avec_poetry&quot;&gt;Intégration avec Poetry&lt;/a&gt;
&lt;ul class=&quot;sectlevel2&quot;&gt;
&lt;li&gt;&lt;a href=&quot;#_installation_de_poetry&quot;&gt;Installation de Poetry&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#_initialisation_du_projet&quot;&gt;Initialisation du projet&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#_ajout_et_installation_de_dépendances&quot;&gt;Ajout et installation de dépendances&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#_publication_avec_poetry&quot;&gt;Publication avec Poetry&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#_builds_reproductibles_avec_docker&quot;&gt;Builds reproductibles avec Docker&lt;/a&gt;
&lt;ul class=&quot;sectlevel2&quot;&gt;
&lt;li&gt;&lt;a href=&quot;#_exemple_de_dockerfile&quot;&gt;Exemple de Dockerfile&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#_intégration_dans_github_actions&quot;&gt;Intégration dans GitHub Actions&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#_publication_conditionnelle&quot;&gt;Publication conditionnelle&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#_automatisation_des_dépendances_avec_renovate_et_dependabot&quot;&gt;Automatisation des dépendances avec Renovate et Dependabot&lt;/a&gt;
&lt;ul class=&quot;sectlevel2&quot;&gt;
&lt;li&gt;&lt;a href=&quot;#_dependabot&quot;&gt;Dependabot&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#_renovate&quot;&gt;Renovate&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#_diagrammes_plantuml&quot;&gt;Diagrammes PlantUML&lt;/a&gt;
&lt;ul class=&quot;sectlevel2&quot;&gt;
&lt;li&gt;&lt;a href=&quot;#_cas_dusage_cicd_avancé&quot;&gt;Cas d’Usage – CI/CD avancé&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#_séquence_publication_conditionnelle&quot;&gt;Séquence – Publication conditionnelle&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#_états_pipeline_cicd&quot;&gt;États – Pipeline CI/CD&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#_déploiement_architecture_cicd&quot;&gt;Déploiement – Architecture CI/CD&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#_conclusion&quot;&gt;Conclusion&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;div id=&quot;preamble&quot;&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Dans les deux premières parties de cette série, nous avons :
- Établi un pipeline CI/CD fonctionnel pour une application Python avec GitHub Actions et PyPI.
- Industrialisé ce pipeline avec des tests multi-versions, une publication progressive via Test PyPI, et des outils de qualité et de sécurité.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Dans cette troisième partie, nous allons aller &lt;strong&gt;au-delà de la simple publication sur PyPI&lt;/strong&gt; pour construire une chaîne de CI/CD complète, robuste et professionnelle avec :
- &lt;strong&gt;Poetry&lt;/strong&gt; pour un packaging moderne et une gestion optimisée des dépendances.
- &lt;strong&gt;Docker&lt;/strong&gt; pour créer des builds reproductibles et multi-plateformes.
- &lt;strong&gt;Publication conditionnelle&lt;/strong&gt; pour gérer des scénarios comme les release candidates.
- &lt;strong&gt;Outils d’automatisation&lt;/strong&gt; (Renovate, Dependabot) pour maintenir le pipeline à jour sans effort.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_intégration_avec_poetry&quot;&gt;Intégration avec Poetry&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Poetry remplace les anciens outils de packaging (setup.py, requirements.txt) en centralisant la gestion des dépendances et du build dans &lt;code&gt;pyproject.toml&lt;/code&gt;.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_installation_de_poetry&quot;&gt;Installation de Poetry&lt;/h3&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;pygments highlight&quot;&gt;&lt;code data-lang=&quot;shell&quot;&gt;# Installer Poetry
curl -sSL https://install.python-poetry.org | python3 -
# Vérifier la version
poetry --version&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_initialisation_du_projet&quot;&gt;Initialisation du projet&lt;/h3&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;pygments highlight&quot;&gt;&lt;code data-lang=&quot;shell&quot;&gt;# Initialiser un nouveau projet avec Poetry
poetry init
# Suivre l&#39;assistant pour renseigner : nom, version, description, licence, dépendances.&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Cela génère un fichier &lt;code&gt;pyproject.toml&lt;/code&gt; :&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;pygments highlight&quot;&gt;&lt;code data-lang=&quot;toml&quot;&gt;[tool.poetry]
name = &quot;playlist-downloader&quot;
version = &quot;0.1.0&quot;
description = &quot;CLI tool for managing YouTube playlists&quot;
authors = [&quot;Christophe Hérolivier &amp;lt;cheroliv@example.com&amp;gt;&quot;]

[tool.poetry.dependencies]
python = &quot;&amp;gt;=3.8&quot;
typer = &quot;^0.9.0&quot;
yt-dlp = &quot;^2023.7.6&quot;
google-api-python-client = &quot;^2.0.0&quot;
google-auth-oauthlib = &quot;^1.0.0&quot;

[tool.poetry.group.dev.dependencies]
pytest = &quot;^7.0&quot;
mypy = &quot;^1.0&quot;
bandit = &quot;^1.7&quot;
safety = &quot;^2.3&quot;
black = &quot;^23.0&quot;
ruff = &quot;^0.1&quot;&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_ajout_et_installation_de_dépendances&quot;&gt;Ajout et installation de dépendances&lt;/h3&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;pygments highlight&quot;&gt;&lt;code data-lang=&quot;shell&quot;&gt;poetry add typer yt-dlp google-api-python-client google-auth-oauthlib
poetry add --group dev pytest mypy black bandit safety ruff&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_publication_avec_poetry&quot;&gt;Publication avec Poetry&lt;/h3&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Poetry gère nativement la publication :&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;pygments highlight&quot;&gt;&lt;code data-lang=&quot;shell&quot;&gt;# Publication sur Test PyPI
poetry publish --build --repository test-pypi

# Publication sur PyPI
poetry publish --build&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Cette commande utilise automatiquement les informations présentes dans &lt;code&gt;pyproject.toml&lt;/code&gt;.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_builds_reproductibles_avec_docker&quot;&gt;Builds reproductibles avec Docker&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour assurer des exécutions identiques en développement, CI/CD et production, Docker s’intègre parfaitement avec Poetry.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_exemple_de_dockerfile&quot;&gt;Exemple de Dockerfile&lt;/h3&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;pygments highlight&quot;&gt;&lt;code data-lang=&quot;dockerfile&quot;&gt;FROM python:3.11-slim

WORKDIR /app
COPY pyproject.toml poetry.lock ./
RUN pip install poetry
RUN poetry install --no-root --only main

COPY . .

CMD [&quot;poetry&quot;, &quot;run&quot;, &quot;python&quot;, &quot;cli.py&quot;]&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Cela garantit :
- Un environnement Python figé.
- Des dépendances verrouillées via &lt;code&gt;poetry.lock&lt;/code&gt;.
- Une image exécutable sur tout système supportant Docker.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_intégration_dans_github_actions&quot;&gt;Intégration dans GitHub Actions&lt;/h3&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;pygments highlight&quot;&gt;&lt;code data-lang=&quot;yaml&quot;&gt;name: Docker Build

on:
  push:
    branches: [main]

jobs:
  build-docker:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - name: Build Docker image
        run: docker build -t ghcr.io/${{ github.repository }}:latest .
      - name: Push Docker image
        run: docker push ghcr.io/${{ github.repository }}:latest&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_publication_conditionnelle&quot;&gt;Publication conditionnelle&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Dans un pipeline professionnel, il faut pouvoir publier uniquement dans certains cas :
- Release candidates vers Test PyPI.
- Versions stables vers PyPI.
- Builds Docker déclenchés uniquement pour &lt;code&gt;main&lt;/code&gt;.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;pygments highlight&quot;&gt;&lt;code data-lang=&quot;yaml&quot;&gt;- name: Publish to Test PyPI
  if: contains(github.ref, &#39;-rc&#39;)
  run: poetry publish --build --repository test-pypi

- name: Publish to PyPI
  if: startsWith(github.ref, &#39;refs/tags/v&#39;)
  run: poetry publish --build&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Cette approche évite les publications accidentelles.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_automatisation_des_dépendances_avec_renovate_et_dependabot&quot;&gt;Automatisation des dépendances avec Renovate et Dependabot&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour éviter que vos dépendances deviennent obsolètes, intégrez des outils de mise à jour automatique.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_dependabot&quot;&gt;Dependabot&lt;/h3&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;pygments highlight&quot;&gt;&lt;code data-lang=&quot;yaml&quot;&gt;version: 2
updates:
  - package-ecosystem: &quot;pip&quot;
    directory: &quot;/&quot;
    schedule:
      interval: &quot;weekly&quot;
  - package-ecosystem: &quot;github-actions&quot;
    directory: &quot;/&quot;
    schedule:
      interval: &quot;weekly&quot;&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Dependabot ouvre des PR chaque semaine pour mettre à jour les dépendances Python et GitHub Actions.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_renovate&quot;&gt;Renovate&lt;/h3&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;pygments highlight&quot;&gt;&lt;code data-lang=&quot;json&quot;&gt;{
  &quot;extends&quot;: [&quot;config:base&quot;],
  &quot;packageRules&quot;: [
    {
      &quot;matchManagers&quot;: [&quot;pip&quot;],
      &quot;groupName&quot;: &quot;python-dependencies&quot;,
      &quot;schedule&quot;: [&quot;before 6am on monday&quot;]
    }
  ]
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Renovate permet un contrôle plus fin : regroupement de dépendances, planification, et règles avancées.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_diagrammes_plantuml&quot;&gt;Diagrammes PlantUML&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_cas_dusage_cicd_avancé&quot;&gt;Cas d’Usage – CI/CD avancé&lt;/h3&gt;
&lt;div class=&quot;imageblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;img src=&quot;images/usecase-cicd.svg&quot; alt=&quot;usecase cicd&quot; width=&quot;819&quot; height=&quot;317&quot;&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_séquence_publication_conditionnelle&quot;&gt;Séquence – Publication conditionnelle&lt;/h3&gt;
&lt;div class=&quot;imageblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;img src=&quot;images/sequence-cicd.svg&quot; alt=&quot;sequence cicd&quot; width=&quot;264&quot; height=&quot;609&quot;&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_états_pipeline_cicd&quot;&gt;États – Pipeline CI/CD&lt;/h3&gt;
&lt;div class=&quot;imageblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;img src=&quot;images/states-cicd.svg&quot; alt=&quot;states cicd&quot; width=&quot;284&quot; height=&quot;608&quot;&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_déploiement_architecture_cicd&quot;&gt;Déploiement – Architecture CI/CD&lt;/h3&gt;
&lt;div class=&quot;imageblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;img src=&quot;images/deployment-cicd.svg&quot; alt=&quot;deployment cicd&quot; width=&quot;535&quot; height=&quot;288&quot;&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_conclusion&quot;&gt;Conclusion&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Dans cette troisième partie, nous avons vu comment :
- Moderniser le packaging Python avec Poetry.
- Garantir des builds reproductibles via Docker.
- Mettre en place une publication conditionnelle.
- Automatiser la mise à jour des dépendances.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Vous disposez désormais d’un pipeline CI/CD &lt;strong&gt;complet, industrialisé et sécurisé&lt;/strong&gt;, prêt à évoluer avec vos projets.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;

